# Fix netlify.toml copy command
# Run: Set-ExecutionPolicy Bypass -Scope Process -Force; .\CPFIX.ps1

$RepoPath = "C:\Users\LionelMosley\Documents\HTML\Synology - DiskStation Monitor"
Set-Location $RepoPath
$b64 = ""
$bytes = [System.Convert]::FromBase64String($b64)
$fullPath = Join-Path $RepoPath "netlify.toml"
[System.IO.File]::WriteAllBytes($fullPath, $bytes)
Write-Host "  updated netlify.toml" -ForegroundColor Green
git add netlify.toml
git commit -m "fix: copy public contents not folder - use cp -r public/. dist/"
git push origin main
if ($LASTEXITCODE -eq 0) {
    Write-Host "`n Done! Visit: https://dsm.4thandbailey.com/synology-monitor.html" -ForegroundColor Green
} else {
    Write-Host "`n Push failed." -ForegroundColor Red
}